// src/components/ProductCard/index.jsx (Предполагаемая структура)
import React from 'react';
import { getImageUrl } from '../../utils/fixUrl';
import { Link } from 'react-router-dom';
import s from './CartItem.module.css';

const ProductCard = ({ id, title, image, price, discont_price }) => {
  const imageUrl = getImageUrl(image);

  // Определяем цену и скидку
  const finalPrice = discont_price !== null ? discont_price : price;
  const originalPrice = discont_price !== null ? price : null;

  const hasDiscount = discont_price !== null && price > discont_price;

  let discountPercent = 0;
  if (hasDiscount) {
    // Расчет процента скидки: ((Оригинальная - Финальная) / Оригинальная) * 100
    discountPercent = Math.round(((price - discont_price) / price) * 100);
  }

  return (
    <Link to={`/products/${id}`} className={s.cardLink}>
        <div className={s.productCard}>

            <div className={s.imageWrapper}>
                <img src={imageUrl} alt={title} className={s.image} />

                {/* Бейдж скидки в правом верхнем углу */}
                {hasDiscount && (
                    <div className={s.discountBadge}>
                        -{discountPercent}%
                    </div>
                )}
            </div>

            <div className={s.content}>
                <p className={s.title}>{title}</p>

                <div className={s.priceContainer}>
                    {/* Крупная финальная цена */}
                    <p className={s.finalPrice}>
                        ${finalPrice.toFixed(2)}
                    </p>

                    {/* Зачеркнутая оригинальная цена */}
                    {originalPrice && (
                        <p className={s.originalPrice}>
                            ${originalPrice.toFixed(2)}
                        </p>
                    )}
                </div>
            </div>

        </div>
    </Link>
  );
};

export default ProductCard;
